function parseJson(text) {
  const cleaned = String(text || '').trim().replace(/^\`\`\`json\s*/i, '').replace(/^\`\`\`/, '').replace(/\`\`\`$/, '').trim();
  const first = cleaned.indexOf('{');
  const last = cleaned.lastIndexOf('}');
  const candidate = first >= 0 && last >= first ? cleaned.slice(first, last + 1) : cleaned;
  return JSON.parse(candidate || '{}');
}

const content =
  (typeof $json.output === 'string' && $json.output) ||
  (typeof $json.text === 'string' && $json.text) ||
  (typeof $json.response === 'string' && $json.response) ||
  $json.choices?.[0]?.message?.content ||
  '{}';
const parsed = typeof $json.output === 'object' && $json.output !== null ? $json.output : parseJson(content);
const context = $('Prepare Chat Context').first().json;
const confidence = typeof parsed.confidence === 'number' ? parsed.confidence : null;
const config = context.config || {};

const resolved = {
  ...context,
  intent: parsed.intent || 'unknown',
  send_action: parsed.send_action || 'none',
  audience_name: parsed.audience_name || config.default_audience_name || '',
  audience_kind: parsed.audience_kind || config.default_audience_kind || 'unknown',
  campaign_name: parsed.campaign_name || '',
  campaign_id: parsed.campaign_id || '',
  campaign_goal: parsed.campaign_goal || '',
  key_message: parsed.key_message || '',
  cta: parsed.cta || config.default_cta || '',
  send_timing: parsed.send_timing || '',
  scheduled_iso: parsed.scheduled_iso || '',
  report_campaign_name: parsed.report_campaign_name || '',
  reactivation_segment: parsed.reactivation_segment || config.default_reactivation_segment || '',
  is_multi_intent: parsed.is_multi_intent === true,
  confidence,
  notes: parsed.notes || '',
};

const missingFields = [];
if (resolved.intent === 'send_campaign' && resolved.send_action === 'create_draft') {
  if (!resolved.audience_name) missingFields.push('audience or segment');
  if (!resolved.campaign_goal) missingFields.push('campaign goal');
  if (!resolved.key_message) missingFields.push('key message or offer');
  if (!resolved.cta) missingFields.push('CTA');
  if (!resolved.send_timing) missingFields.push('send timing');
} else if (resolved.intent === 'send_campaign' && resolved.send_action === 'send_draft') {
  if (!resolved.campaign_id) missingFields.push('draft campaign ID');
} else if (resolved.intent === 'send_campaign' && resolved.send_action === 'schedule_draft') {
  if (!resolved.campaign_id) missingFields.push('draft campaign ID');
  if (!resolved.scheduled_iso && !resolved.send_timing) missingFields.push('schedule time');
} else if (resolved.intent === 'reactivate_cold') {
  if (!resolved.reactivation_segment) missingFields.push('reactivation segment');
}

const needsClarification =
  resolved.intent === 'unknown' ||
  resolved.is_multi_intent === true ||
  confidence === null ||
  confidence < 0.75 ||
  missingFields.length > 0;

let clarificationQuestion = parsed.clarification_question || '';
if (!clarificationQuestion) {
  if (resolved.intent === 'unknown' || resolved.is_multi_intent === true) {
    clarificationQuestion = 'Which one task do you want: send campaign, report campaign, or reactivate cold subscribers?';
  } else if (missingFields.length > 0) {
    clarificationQuestion = 'I need these details: ' + missingFields.join(', ') + '.';
  } else {
    clarificationQuestion = 'I need one clear email task at a time.';
  }
}

return [{
  json: {
    ...resolved,
    clarification_question: clarificationQuestion,
    missing_fields: missingFields,
    needs_clarification: needsClarification,
  },
}];

const missing = $json.missing_fields || [];
const known = [
  'Intent: ' + ($json.intent || 'unknown'),
  $json.send_action && $json.send_action !== 'none' ? 'Action: ' + $json.send_action : null,
  $json.audience_name ? 'Audience: ' + $json.audience_name : null,
  $json.campaign_goal ? 'Goal: ' + $json.campaign_goal : null,
  $json.key_message ? 'Key message: ' + $json.key_message : null,
  $json.cta ? 'CTA: ' + $json.cta : null,
  $json.send_timing ? 'Timing: ' + $json.send_timing : null,
  $json.campaign_id ? 'Campaign ID: ' + $json.campaign_id : null,
  $json.report_campaign_name ? 'Report campaign: ' + $json.report_campaign_name : null,
  $json.reactivation_segment ? 'Reactivation segment: ' + $json.reactivation_segment : null,
].filter(Boolean);

const prompt =
  $json.intent === 'unknown' || $json.is_multi_intent === true
    ? [
        'I already have the business config. I need one clear task.',
        'Reply with exactly one of these intents and any needed details:',
        '- send campaign',
        '- report campaign',
        '- reactivate cold subscribers',
      ].join('\n')
    : [
        'I already have the business config. I only need the missing details.',
        'Missing: ' + missing.join(', ') + '.',
        '',
        ...known,
        '',
        'Reply in one message with only the missing details.',
      ].join('\n');

return [{
  json: {
    ...$json,
    intake_round: 1,
    intake_prompt: prompt,
  },
}];

function parseJson(text) {
  const cleaned = String(text || '').trim().replace(/^\`\`\`json\s*/i, '').replace(/^\`\`\`/, '').replace(/\`\`\`$/, '').trim();
  const first = cleaned.indexOf('{');
  const last = cleaned.lastIndexOf('}');
  const candidate = first >= 0 && last >= first ? cleaned.slice(first, last + 1) : cleaned;
  return JSON.parse(candidate || '{}');
}

const content =
  (typeof $json.output === 'string' && $json.output) ||
  (typeof $json.text === 'string' && $json.text) ||
  (typeof $json.response === 'string' && $json.response) ||
  $json.choices?.[0]?.message?.content ||
  '{}';
const parsed = typeof $json.output === 'object' && $json.output !== null ? $json.output : parseJson(content);
const previous = $('Build Context Prompt 1').first().json;
const config = previous.config || {};

const resolved = {
  ...previous,
  intent: parsed.intent || previous.intent || 'unknown',
  send_action: parsed.send_action || previous.send_action || 'none',
  audience_name: parsed.audience_name || previous.audience_name || config.default_audience_name || '',
  audience_kind: parsed.audience_kind || previous.audience_kind || config.default_audience_kind || 'unknown',
  campaign_name: parsed.campaign_name || previous.campaign_name || '',
  campaign_id: parsed.campaign_id || previous.campaign_id || '',
  campaign_goal: parsed.campaign_goal || previous.campaign_goal || '',
  key_message: parsed.key_message || previous.key_message || '',
  cta: parsed.cta || previous.cta || config.default_cta || '',
  send_timing: parsed.send_timing || previous.send_timing || '',
  scheduled_iso: parsed.scheduled_iso || previous.scheduled_iso || '',
  report_campaign_name: parsed.report_campaign_name || previous.report_campaign_name || '',
  reactivation_segment: parsed.reactivation_segment || previous.reactivation_segment || config.default_reactivation_segment || '',
  notes: parsed.notes || previous.notes || '',
};

const missingFields = [];
if (resolved.intent === 'send_campaign' && resolved.send_action === 'create_draft') {
  if (!resolved.audience_name) missingFields.push('audience or segment');
  if (!resolved.campaign_goal) missingFields.push('campaign goal');
  if (!resolved.key_message) missingFields.push('key message or offer');
  if (!resolved.cta) missingFields.push('CTA');
  if (!resolved.send_timing) missingFields.push('send timing');
} else if (resolved.intent === 'send_campaign' && resolved.send_action === 'send_draft') {
  if (!resolved.campaign_id) missingFields.push('draft campaign ID');
} else if (resolved.intent === 'send_campaign' && resolved.send_action === 'schedule_draft') {
  if (!resolved.campaign_id) missingFields.push('draft campaign ID');
  if (!resolved.scheduled_iso && !resolved.send_timing) missingFields.push('schedule time');
} else if (resolved.intent === 'reactivate_cold') {
  if (!resolved.reactivation_segment) missingFields.push('reactivation segment');
}

return [{
  json: {
    ...resolved,
    missing_fields: missingFields,
  },
}];

return [{
  json: {
    reply_text: [
      'Failed.',
      'Task: context fill',
      'Reason: the request is still incomplete after one context round.',
      'Next step: send one message with one clear intent and the missing details.',
    ].join('\n'),
  },
}];

const context = $('Send Action Switch').first().json;
const desired = (context.audience_name || '').trim().toLowerCase();
const groups = $('Fetch Groups').first().json.data || [];
const segments = $('Fetch Segments').first().json.data || [];

function findExactOrPartial(list) {
  return (
    list.find((item) => (item.name || '').trim().toLowerCase() === desired) ||
    list.find((item) => (item.name || '').trim().toLowerCase().includes(desired))
  );
}

let match = null;
let kind = 'unknown';

if (context.audience_kind === 'group') {
  match = findExactOrPartial(groups);
  kind = match ? 'group' : 'unknown';
} else if (context.audience_kind === 'segment') {
  match = findExactOrPartial(segments);
  kind = match ? 'segment' : 'unknown';
} else {
  match = findExactOrPartial(segments);
  kind = match ? 'segment' : 'unknown';
  if (!match) {
    match = findExactOrPartial(groups);
    kind = match ? 'group' : 'unknown';
  }
}

return [{
  json: {
    ...context,
    audience_match: match
      ? {
          id: match.id,
          name: match.name,
          kind,
        }
      : null,
  },
}];

return [{
  json: {
    reply_text: 'Failed.\nTask: send campaign\nReason: MailerLite audience was not found.\nNext step: check both the exact group or segment name in Mailerlite and your input and please try again.',
  },
}];

const context = $('Build Send Draft Payload').first().json;
const campaign = $json.data || $json;
const campaignId = campaign.id || '';
const taskId = 'EMM-' + Date.now();

const notes = JSON.stringify({
  session_id: context.session_id || '',
  audience_name: context.audience_match?.name || context.audience_name,
  audience_kind: context.audience_match?.kind || context.audience_kind,
  send_timing: context.send_timing,
  requested_schedule: context.scheduled_iso || '',
  preview_text: context.preview_text,
});

return [{
  json: {
    reply_text: [
      'Done.',
      'Campaign: ' + (campaign.name || context.campaign_payload.name),
      'Status: draft created',
      'Audience: ' + (context.audience_match?.name || context.audience_name),
      'Campaign ID: ' + campaignId,
      'Next step: reply "SEND CAMPAIGN ' + campaignId + '" to send immediately, or "SCHEDULE CAMPAIGN ' + campaignId + ' 2026-04-18T09:00:00Z" to schedule.',
    ].join('\n'),
    log_row: {
      task_id: taskId,
      campaign_id: String(campaignId),
      task_type: 'send_campaign_draft',
      status: 'done',
      timestamp: new Date().toISOString(),
      notes,
    },
  },
}];

return [{
  json: {
    reply_text: 'Failed.\nTask: send draft\nReason: matching draft campaign was not found.\nNext step: use the exact campaign ID from the draft confirmation message.',
  },
}];

const action = $json.send_action;
let payload = { delivery: 'instant' };

if (action === 'schedule_draft') {
  const iso = $json.scheduled_iso || '';
  const date = new Date(iso);
  if (!iso || Number.isNaN(date.getTime())) {
    throw new Error('A valid ISO schedule time is required for schedule_draft');
  }
  payload = {
    delivery: 'scheduled',
    schedule: {
      date: date.toISOString().slice(0, 10),
      hours: date.toISOString().slice(11, 13),
      minutes: date.toISOString().slice(14, 16),
    },
  };
}

return [{
  json: {
    ...$json,
    delivery_payload: payload,
  },
}];

const context = $('Build Delivery Payload').first().json;
const campaign = $json.data || $json;
const sendKind = context.send_action === 'schedule_draft' ? 'scheduled' : 'sent';
const baseTaskType =
  String(context.draft_campaign?.name || '').toLowerCase().includes('reactivate')
    ? 'reactivate_sent'
    : 'send_campaign_delivery';

const notes = JSON.stringify({
  session_id: context.session_id || '',
  campaign_name: campaign.name || context.draft_campaign?.name || '',
  followup_due_at:
    baseTaskType === 'reactivate_sent'
      ? new Date(Date.now() + 48 * 60 * 60 * 1000).toISOString()
      : '',
});

return [{
  json: {
    reply_text: [
      'Done.',
      'Campaign: ' + (campaign.name || context.draft_campaign?.name || ''),
      'Status: ' + sendKind,
      'Campaign ID: ' + (campaign.id || context.draft_campaign?.id || ''),
    ].join('\n'),
    log_row: {
      task_id: 'EMM-' + Date.now(),
      campaign_id: String(campaign.id || context.draft_campaign?.id || ''),
      task_type: baseTaskType,
      status: baseTaskType === 'reactivate_sent' ? 'sent_pending_followup' : sendKind,
      timestamp: new Date().toISOString(),
      notes,
    },
  },
}];

const context = $('Parse Intent').first().json;
const campaigns = $json.data || [];
const desired = (context.report_campaign_name || '').trim().toLowerCase();

let campaign = null;
if (desired) {
  campaign =
    campaigns.find((item) => String(item.name || '').trim().toLowerCase() === desired) ||
    campaigns.find((item) => String(item.name || '').trim().toLowerCase().includes(desired)) ||
    null;
}
if (!campaign && campaigns.length) {
  campaign = campaigns[0];
}

return [{
  json: {
    ...context,
    report_campaign: campaign,
  },
}];

return [{
  json: {
    reply_text: 'Failed.\nTask: report campaign\nReason: no sent campaign matched that request.\nNext step: use the latest campaign name or leave the message general to report on the most recent send.',
  },
}];

function parseJson(text) {
  const cleaned = String(text || '').trim().replace(/^\`\`\`json\s*/i, '').replace(/^\`\`\`/, '').replace(/\`\`\`$/, '').trim();
  const first = cleaned.indexOf('{');
  const last = cleaned.lastIndexOf('}');
  const candidate = first >= 0 && last >= first ? cleaned.slice(first, last + 1) : cleaned;
  return JSON.parse(candidate || '{}');
}

const content =
  (typeof $json.output === 'string' && $json.output) ||
  (typeof $json.text === 'string' && $json.text) ||
  (typeof $json.response === 'string' && $json.response) ||
  $json.choices?.[0]?.message?.content ||
  '{}';
const parsed = typeof $json.output === 'object' && $json.output !== null ? $json.output : parseJson(content);
const context = $('Resolve Report Campaign').first().json;
const campaign = context.report_campaign || {};
const stats = campaign.stats || campaign.emails?.[0]?.stats || {};
return [{
  json: {
    ...context,
    report_stats: stats,
    report_headline: parsed.headline || 'Report ready.',
    report_summary: parsed.summary || '',
  },
}];

const stats = $json.report_stats || {};
const values = [
  Number((stats.open_rate?.float || 0) * 100).toFixed(1),
  Number((stats.click_rate?.float || 0) * 100).toFixed(1),
  Number(stats.unsubscribes_count || 0),
  Number((stats.hard_bounces_count || 0) + (stats.soft_bounces_count || 0)),
].map(Number);

const chart = {
  type: 'bar',
  data: {
    labels: ['Open Rate', 'CTR', 'Unsubscribes', 'Bounces'],
    datasets: [
      {
        label: 'Campaign performance',
        data: values,
        backgroundColor: ['#4472C4', '#5B8FF9', '#F6BD16', '#E8684A'],
      },
    ],
  },
  options: {
    plugins: {
      legend: { display: false },
    },
    scales: {
      y: {
        beginAtZero: true,
      },
    },
  },
};

return [{
  json: {
    ...$json,
    chart_url: 'https://quickchart.io/chart?c=' + encodeURIComponent(JSON.stringify(chart)),
  },
}];

const stats = $json.report_stats || {};
return [{
  json: {
    reply_text: [
      $json.report_headline,
      'Campaign: ' + ($json.report_campaign?.name || ''),
      'Open rate: ' + (stats.open_rate?.string || '0%'),
      'CTR: ' + (stats.click_rate?.string || '0%'),
      'Unsubscribes: ' + (stats.unsubscribes_count || 0),
      'Bounces: ' + ((stats.hard_bounces_count || 0) + (stats.soft_bounces_count || 0)),
      'Summary: ' + $json.report_summary,
      $json.chart_url ? 'Chart: ' + $json.chart_url : '',
    ]
      .filter(Boolean)
      .join('\n'),
    log_row: {
      task_id: 'EMM-' + Date.now(),
      campaign_id: String($json.report_campaign?.id || ''),
      task_type: 'report_campaign',
      status: 'done',
      timestamp: new Date().toISOString(),
      notes: JSON.stringify({ session_id: $json.session_id || '', chart_url: $json.chart_url }),
    },
  },
}];

const context = $('Parse Intent').first().json;
const desired = (context.reactivation_segment || 'Inactive').trim().toLowerCase();
const segments = $json.data || [];
const match =
  segments.find((item) => String(item.name || '').trim().toLowerCase() === desired) ||
  segments.find((item) => String(item.name || '').trim().toLowerCase().includes(desired)) ||
  null;

return [{
  json: {
    ...context,
    reactivation_match: match,
  },
}];

return [{
  json: {
    reply_text: 'Failed.\nTask: reactivate cold subscribers\nReason: MailerLite inactive segment was not found.\nNext step: create or rename the segment before running reactivation.',
  },
}];

