  (typeof $json.text === 'string' && $json.text) ||
  (typeof $json.response === 'string' && $json.response) ||
  $json.choices?.[0]?.message?.content ||
  '{}';
const parsed = typeof $json.output === 'object' && $json.output !== null ? $json.output : parseJson(content);
const context = $('Resolve Reactivation Segment').first().json;

function markdownToHtml(markdown) {
  return String(markdown || '')
    .split(/\n{2,}/)
    .map((block) => '<p>' + block.replace(/\n/g, '<br>') + '</p>')
    .join('');
}

return [{
  json: {
    ...context,
    subject: parsed.subject || '',
    preview_text: parsed.preview_text || '',
    body_markdown: parsed.body_markdown || '',
    body_html: markdownToHtml(parsed.body_markdown || ''),
  },
}];

const campaignName = 'REACTIVATE | ' + ($json.reactivation_match?.name || 'Inactive') + ' | ' + new Date().toISOString().slice(0, 10);
return [{
  json: {
    ...$json,
    campaign_payload: {
      name: campaignName.slice(0, 255),
      type: 'regular',
      emails: [
        {
          subject: $json.subject,
          from_name: $json.sender_name,
          from: $json.sender_email,
          reply_to: $json.reply_to,
          content: '<div data-preview-text="' + $json.preview_text.replace(/"/g, '&quot;') + '">' + $json.body_html + '</div>',
        },
      ],
      segments: [String($json.reactivation_match.id)],
    },
  },
}];

const context = $('Build Reactivation Payload').first().json;
const campaign = $json.data || $json;
const notes = JSON.stringify({
  session_id: context.session_id || '',
  segment_name: context.reactivation_match?.name || 'Inactive',
  cold_rule: 'no opens in 4 days',
});

return [{
  json: {
    reply_text: [
      'Done.',
      'Campaign: ' + (campaign.name || context.campaign_payload.name),
      'Status: draft created',
      'Audience: ' + (context.reactivation_match?.name || 'Inactive'),
      'Campaign ID: ' + (campaign.id || ''),
      'Next step: reply "SEND CAMPAIGN ' + (campaign.id || '') + '" to send the reactivation draft.',
    ].join('\n'),
    log_row: {
      task_id: 'EMM-' + Date.now(),
      campaign_id: String(campaign.id || ''),
      task_type: 'reactivate_cold_draft',
      status: 'done',
      timestamp: new Date().toISOString(),
      notes,
    },
  },
}];

function parseJson(text) {
  const cleaned = String(text || '').trim().replace(/^\`\`\`json\s*/i, '').replace(/^\`\`\`/, '').replace(/\`\`\`$/, '').trim();
  const first = cleaned.indexOf('{');
  const last = cleaned.lastIndexOf('}');
  const candidate = first >= 0 && last >= first ? cleaned.slice(first, last + 1) : cleaned;
  return JSON.parse(candidate || '{}');
}

const content =
  (typeof $json.output === 'string' && $json.output) ||
  (typeof $json.text === 'string' && $json.text) ||
  (typeof $json.response === 'string' && $json.response) ||
  $json.choices?.[0]?.message?.content ||
  '{}';
const parsed = typeof $json.output === 'object' && $json.output !== null ? $json.output : parseJson(content);
const context = $('Resolve Send Audience').first().json;

function markdownToHtml(markdown) {
  return String(markdown || '')
    .split(/\n{2,}/)
    .map((block) => '<p>' + block.replace(/\n/g, '<br>') + '</p>')
    .join('');
}

return [{
  json: {
    ...context,
    subject: parsed.subject || '',
    preview_text: parsed.preview_text || '',
    body_markdown: parsed.body_markdown || '',
    body_html: markdownToHtml(parsed.body_markdown || ''),
    rationale: parsed.rationale || '',
  },
}];

const audience = $('Resolve Send Audience').first().json.audience_match;
const campaignName =
  $json.campaign_name ||
  ('NOOM | ' + audience.name + ' | ' + $json.campaign_goal).slice(0, 255);

const payload = {
  name: campaignName,
  type: 'regular',
  emails: [
    {
      subject: $json.subject,
      from_name: $json.sender_name,
      from: $json.sender_email,
      reply_to: $json.reply_to,
      content: '<div data-preview-text="' + $json.preview_text.replace(/"/g, '&quot;') + '">' + $json.body_html + '</div>',
    },
  ],
};

if (audience.kind === 'segment') {
  payload.segments = [String(audience.id)];
} else {
  payload.groups = [String(audience.id)];
}

return [{
  json: {
    ...$json,
    campaign_payload: payload,
  },
}];
